import { supabase } from './supabase';
export default {
  async getAll() {
    const {
      data,
      error
    } = await supabase.from('product_rental_availability').select('*').order('product_name', {
      ascending: true
    });
    if (error) throw error;
    return data || [];
  },
  async getByProductId(productId) {
    const {
      data,
      error
    } = await supabase.from('product_rental_availability').select('*').eq('product_id', productId).maybeSingle();
    if (error) throw error;
    return data;
  },
  async create(productData) {
    const {
      data,
      error
    } = await supabase.from('product_rental_availability').insert(productData).select().single();
    if (error) throw error;
    return data;
  },
  async update(id, updates) {
    const {
      data,
      error
    } = await supabase.from('product_rental_availability').update({
      ...updates,
      updated_at: new Date().toISOString()
    }).eq('id', id).select().single();
    if (error) throw error;
    return data;
  },
  async delete(id) {
    const {
      error
    } = await supabase.from('product_rental_availability').delete().eq('id', id);
    if (error) throw error;
  }
};
